'use strict';(function(){var e=new Date;e.setDate(e.getDate()+30);var t=e.getTime(),n=setInterval(function(){var e=new Date().getTime(),a=t-e,r=Math.floor(a/864e5),o=Math.floor(a%864e5/36e5),l=Math.floor(a%36e5/6e4),m=Math.floor(a%6e4/1e3);document.getElementById('time').innerHTML=r+'d '+o+'h '+l+'m '+m+'s ',document.getElementById('days').innerHTML=r,a<0&&(clearInterval(n),document.getElementById('time').innerHTML='Launched!')},1e3)})();